const uploadResp = $input.first().json;
const fileUri = uploadResp?.file?.uri;
const mimeType = uploadResp?.file?.mimeType || 'image/jpeg';

if (!fileUri) {
  throw new Error('Gemini Files upload failed. Response: ' + JSON.stringify(uploadResp).substring(0, 500));
}

const caption = $('Telegram Trigger').first().json.message.caption || '';
const userHint = caption ? '\n\nUser note: "' + caption + '"' : '';

const prompt = 'Analyze this food or drink image and return ONLY valid JSON, no markdown, no explanation.' + userHint + '\n\nFor meal_type use EXACTLY one of these values based on content and time:\n- "morning_fuel" — breakfast/morning meal (6am-11am)\n- "midday_fuel" — lunch/midday meal (11am-3pm)\n- "evening_fuel" — dinner/evening meal (6pm-10pm)\n- "evening_snack" — afternoon/evening snack, fruits (3pm-6pm)\n- "beverage" — drinks only: coffee, tea, whey protein shake, fruit juice, energy drink, smoothie\n\nReturn this exact structure:\n{\n  "meal_type": "midday_fuel",\n  "items": [{"name": "Dal Rice", "portion": "1 bowl", "calories": 350, "protein": 12, "carbs": 55, "fat": 8, "sugar": 3, "fiber": 6}],\n  "totals": {"calories": 350, "protein": 12, "carbs": 55, "fat": 8, "sugar": 3, "fiber": 6},\n  "health_rating": 4,\n  "notes": "Brief comment"\n}';

const geminiBody = {
  contents: [{
    parts: [
      { fileData: { fileUri, mimeType } },
      { text: prompt }
    ]
  }],
  generationConfig: { temperature: 0.3, maxOutputTokens: 8192 }
};

return [{ json: { geminiBody, fileUri } }];

const raw = $input.first().json;
const chatId = $('Telegram Trigger').first().json.message.chat.id;
const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

// Capture actual Gemini API errors (neverError:true keeps them out of node errors)
if (raw.error) {
  const msg = raw.error.message || JSON.stringify(raw.error).substring(0, 300);
  const status = raw.error.status || raw.error.code || '?';
  return [{ json: {
    reply: `❌ <b>Gemini error [${esc(String(status))}]:</b>\n${esc(msg)}`,
    chat_id: chatId,
    meal_id: '', date: new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' }),
    time: new Date().toLocaleTimeString('en-GB', { timeZone: 'Asia/Kolkata', hour12: false }),
    meal_type: 'error', food_items: 'gemini_error',
    calories: 0, protein_g: 0, carbs_g: 0, fat_g: 0, sugar_g: 0, fiber_g: 0
  }}];
}

const text = raw.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

let parsed;
try {
  const clean = text.replace(/```json\n?|```/g, '').trim();
  const match = clean.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
} catch(e) {
  parsed = {};
}

const now = new Date();
const mealId = 'meal_' + now.getTime();
const items = (parsed.items || []).map(i => `• ${esc(i.name)} (${esc(i.portion)}): ${i.calories} kcal`).join('\n');
const t = parsed.totals || {};
const sugarAlert = (t.sugar || 0) > 24 ? `\n\n⚠️ High sugar: ${t.sugar}g (limit: 30g/day)` : '';
const stars = '⭐'.repeat(Math.min(parsed.health_rating || 3, 5));

const reply = `🍽️ <b>Meal Logged!</b>\n\n${items}\n\n<b>Totals:</b>\nCalories: ${t.calories || 0} kcal\nProtein: ${t.protein || 0}g | Carbs: ${t.carbs || 0}g | Fat: ${t.fat || 0}g\n\nHealth: ${stars}\n💡 ${esc(parsed.notes || '')}${sugarAlert}`;

return [{ json: {
  reply,
  chat_id: chatId,
  meal_id: mealId,
  date: now.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' }),
  time: now.toLocaleTimeString('en-GB', { timeZone: 'Asia/Kolkata', hour12: false }),
  meal_type: parsed.meal_type || 'meal',
  food_items: (parsed.items || []).map(i => i.name).join(', '),
  calories: t.calories || 0,
  protein_g: t.protein || 0,
  carbs_g: t.carbs || 0,
  fat_g: t.fat || 0,
  sugar_g: t.sugar || 0,
  fiber_g: t.fiber || 0
}}];

const raw = ($input.first().json.message.text || '');
const text = raw.replace(/^\/water\s*/i, '').toLowerCase();
const chatId = $input.first().json.message.chat.id;
const numMatch = text.match(/([\d.]+)/);
let ml;
if (numMatch) {
  const num = parseFloat(numMatch[1]);
  ml = num < 20 ? Math.round(num * 250) : Math.round(num);
} else {
  ml = 250;
}
if (ml < 50) ml = 50;
if (ml > 2000) ml = 2000;
const now = new Date();
return [{ json: {
  chat_id: chatId, ml,
  date: now.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' }),
  time: now.toLocaleTimeString('en-GB', { timeZone: 'Asia/Kolkata', hour12: false })
}}];

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
const rows = $input.all();
const todayTotal = rows
  .filter(r => r.json.date === today)
  .reduce((sum, r) => sum + (parseFloat(r.json.ml) || 0), 0);

const target = 3000;
const remaining = Math.max(0, target - todayTotal);
const percent = Math.round((todayTotal / target) * 100);
// Bar: 10 squares, each = 200ml
const filled = Math.min(Math.floor(todayTotal / 200), 10);
let bar = '';
for (let i = 0; i < 10; i++) bar += i < filled ? '🟦' : '⬜';

let msg = `💧 *Water logged!*\n\n${bar}\nToday: *${todayTotal}ml / ${target}ml* (${percent}%)`;
if (remaining > 0) msg += `\n${remaining}ml more to reach your goal!`;
else msg += `\n🎉 Daily water goal reached!`;

const chatId = $('Parse Water Command').first().json.chat_id;
return [{ json: { reply: msg, chat_id: chatId } }];

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
const text = ($('Telegram Trigger').first().json.message.text || '').toLowerCase();

let days = 1, periodLabel = 'Today';
if (text.includes('month')) { days = 30; periodLabel = 'This Month (30 days)'; }
else if (text.includes('week')) { days = 7; periodLabel = 'This Week (7 days)'; }

const startDate = new Date();
startDate.setDate(startDate.getDate() - (days - 1));
const startDateStr = startDate.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
const inRange = date => date >= startDateStr && date <= today;

const meals = $input.all().filter(r => inRange(r.json.date));
const calTarget = 2000 * days;
const totalCal = meals.reduce((s, r) => s + (parseFloat(r.json.calories) || 0), 0);
const totalProtein = meals.reduce((s, r) => s + (parseFloat(r.json.protein_g) || 0), 0);
const totalCarbs = meals.reduce((s, r) => s + (parseFloat(r.json.carbs_g) || 0), 0);
const totalFat = meals.reduce((s, r) => s + (parseFloat(r.json.fat_g) || 0), 0);
const totalSugar = meals.reduce((s, r) => s + (parseFloat(r.json.sugar_g) || 0), 0);

const calPct = Math.round((totalCal / calTarget) * 100);
const calBars = Math.min(Math.round((totalCal / calTarget) * 10), 10);
let calBar = ''; for (let i = 0; i < 10; i++) calBar += i < calBars ? '🟩' : '⬜';

const chatId = $('Telegram Trigger').first().json.message.chat.id;
const dateRange = days === 1
  ? new Date().toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'short' })
  : `${startDateStr} → ${today}`;

let msg = `📊 <b>${periodLabel}</b>\n<i>${dateRange}</i>\n\n`;
msg += `🍽️ <b>Calories</b>\n${calBar}\n`;
if (days > 1) msg += `Total: <b>${totalCal} kcal</b> | Avg: <b>${Math.round(totalCal/days)} kcal/day</b> (${calPct}%)\n`;
else msg += `${totalCal} / ${calTarget} kcal (${calPct}%)\n`;
msg += `Protein: ${totalProtein}g | Carbs: ${totalCarbs}g | Fat: ${totalFat}g`;

if (days === 1) {
  const mealList = meals.map(r => `  • ${r.json.meal_type}: ${r.json.food_items} (${r.json.calories} kcal)`).join('\n') || '  No meals logged yet';
  msg += `\n\n🥗 <b>Meals (${meals.length})</b>\n${mealList}`;
} else {
  msg += `\n\n🥗 <b>Meals logged: ${meals.length}</b> (avg ${(meals.length/days).toFixed(1)}/day)`;
}

if (totalSugar > 30 * days) msg += `\n\n⚠️ High sugar: ${totalSugar}g (limit: ${30 * days}g)`;

return [{ json: { reply: msg, chat_id: chatId } }];

const msg = $input.first().json.message;
const foodText = (msg.text || '').replace(/^/food\s*/i, '').trim();

const prompt = 'You are a nutrition expert. Analyze the following food or drink description and return ONLY valid JSON, no markdown, no explanation.

For meal_type use EXACTLY one of: "morning_fuel" (breakfast 6am-11am), "midday_fuel" (lunch 11am-3pm), "evening_fuel" (dinner 6pm-10pm), "evening_snack" (snack/fruits 3pm-6pm), "beverage" (coffee, tea, whey protein, juice, energy drink, smoothie).

Food/Drink description: "' + foodText + '"

Return this exact structure:
{
  "meal_type": "midday_fuel",
  "items": [{"name": "Dal Rice", "portion": "1 bowl", "calories": 350, "protein": 12, "carbs": 55, "fat": 8, "sugar": 3, "fiber": 6}],
  "totals": {"calories": 350, "protein": 12, "carbs": 55, "fat": 8, "sugar": 3, "fiber": 6},
  "health_rating": 4,
  "notes": "Brief comment"
}

If the text is not a food description, return:
{"items": [], "totals": {"calories": 0, "protein": 0, "carbs": 0, "fat": 0, "sugar": 0, "fiber": 0}, "meal_type": "unknown", "health_rating": 0, "notes": "Not recognised as food or drink. Type /food [what you ate/drank] or send a photo."}';

const geminiBody = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { temperature: 0.3, maxOutputTokens: 8192 }
};

return [{ json: { geminiBody } }];

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
const text = ($('Telegram Trigger').first().json.message.text || '').toLowerCase();

let days = 1, periodLabel = 'Today';
if (text.includes('month')) { days = 30; periodLabel = 'This Month (30 days)'; }
else if (text.includes('week')) { days = 7; periodLabel = 'This Week (7 days)'; }

const startDate = new Date();
startDate.setDate(startDate.getDate() - (days - 1));
const startDateStr = startDate.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
const inRange = d => d >= startDateStr && d <= today;

const rows = $input.all().filter(r => inRange(r.json.date));
const target = 3000 * days;
const total = rows.reduce((s, r) => s + (parseFloat(r.json.ml) || 0), 0);
const pct = Math.round((total / target) * 100);

const filled = Math.min(Math.floor((total / target) * 10), 10);
let bar = ''; for (let i = 0; i < 10; i++) bar += i < filled ? '🟦' : '⬜';

const chatId = $('Telegram Trigger').first().json.message.chat.id;
const dateRange = days === 1
  ? new Date().toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'short' })
  : `${startDateStr} → ${today}`;

let msg = `💧 *Water Summary — ${periodLabel}*\n_${dateRange}_\n\n${bar}\n`;

if (days > 1) {
  msg += `Total: *${total}ml* | Avg: *${Math.round(total / days)}ml/day*\n`;
  msg += `Target: ${target}ml (${pct}%)`;
} else {
  msg += `${total}ml / ${target}ml (${pct}%)`;
  const remaining = Math.max(0, target - total);
  if (remaining > 0) msg += `\n${remaining}ml more to reach your goal!`;
  else msg += `\n🎉 Daily water goal reached!`;
}

if (days === 1 && rows.length > 0) {
  const logs = rows.map(r => `  • ${r.json.time}: ${r.json.ml}ml`).join('\n');
  msg += `\n\n🕐 *Logs (${rows.length})*\n${logs}`;
}

return [{ json: { reply: msg, chat_id: chatId } }];

const msg = $input.item.json.message || {};
const chatId = msg.chat?.id;
const text = (msg.text || '').trim();

const lower = text.toLowerCase();

if (lower.startsWith('/resume')) {
  const jd = text.replace(/^\/resume\s*/i, '').trim();
  if (!jd) {
    return [{ json: { type: 'prompt_jd', chatId, text } }];
  }
  return [{ json: { type: 'resume', chatId, jobDescription: jd } }];
}

if (text.length > 200 && !text.startsWith('/')) {
  return [{ json: { type: 'resume', chatId, jobDescription: text } }];
}

return [];

const claudeResponse = $input.item.json;
const promptData = $('Resume Build Prompt').item.json;

let latexCode = '';
if (claudeResponse.content && Array.isArray(claudeResponse.content)) {
  for (const block of claudeResponse.content) {
    if (block.type === 'text' && block.text) {
      latexCode = block.text;
      break;
    }
  }
}

if (!latexCode) {
  throw new Error('Claude returned empty response: ' + JSON.stringify(claudeResponse).substring(0, 200));
}

latexCode = latexCode
  .replace(/^```(?:latex|tex|\s*)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

if (!latexCode.includes('\\documentclass')) {
  throw new Error('Invalid LaTeX from Claude: ' + latexCode.substring(0, 200));
}

if (!latexCode.includes('\\end{document}')) {
  latexCode += '\n\\end{document}';
}

const model = claudeResponse.model || 'claude-sonnet-4-6';
const inputTokens = claudeResponse.usage?.input_tokens || 0;
const outputTokens = claudeResponse.usage?.output_tokens || 0;
const elapsed = Math.round((Date.now() - (promptData.startTime || Date.now())) / 1000);

return [{ json: { latexCode, chatId: promptData.chatId, model, inputTokens, outputTokens, elapsedSec: elapsed, lineCount: latexCode.split('\n').length } }];
